questionvariables.text:
/* 1. Define segments along the baseline AD */
/* AB = d1, BC = d2, CD = d3 */
d1: 4 + rand(4);
d2: 5 + rand(5);
d3: 4 + rand(4);

/* 2. Define perpendicular offsets (heights) */
h1: 3 + rand(4); /* Offset at point B to vertex E */
h2: 5 + rand(4); /* Offset at point C to vertex F */

/* 3. Calculate areas of individual shapes */
/* Triangle 1 (Left): 1/2 * d1 * h1 */
area1: 1/2 * d1 * h1;

/* Trapezium (Middle): 1/2 * (h1 + h2) * d2 */
area2: 1/2 * (h1 + h2) * d2;

/* Triangle 2 (Right): 1/2 * d3 * h2 */
area3: 1/2 * d3 * h2;

/* 4. Total Area */
ta: area1 + area2 + area3;
